import {
    LOCALSTORAGE_COOKIE_CONSENT_KEY,
    LOCALSTORAGE_COOKIE_CONSENT_VALUE,
    LOCALSTORAGE_MESSAGE_KEY,
} from './constants';

export const isObject = (obj) =>
    typeof obj === 'object' && obj?.constructor === Object;

export const isObjectEmpty = (obj) =>
    isObject(obj) && Object.keys(obj).length === 0;

export const isObjectNotEmpty = (obj) =>
    isObject(obj) && Object.keys(obj).length > 0;

export const getFormattedDateForLanguage = (ISO8601date, language, dateStyle = 'long') => {
    const date = new Date(ISO8601date);

    return date.toLocaleDateString(language, { dateStyle });
};

export const getYoutubeVideoIdFromVideoUrl = (videoUrl) => {
    const result = videoUrl.match(/d\/(\w+)\?rel=\d+/);
    if (result?.length > 1) {
        return result[1];
    }

    return null;
};

export const generateSeoFriendlyVideoUrl = (videoUrl) => {
    // TODO add other types of videos
    if (videoUrl?.includes?.('youtube.')) {
        const youtubeId = getYoutubeVideoIdFromVideoUrl(videoUrl);
        if (youtubeId) {
            return `https://www.youtube.com/v/${youtubeId}`;
        }
    }

    return '';
};

// example: snackbar_message_key -> your_comment_submitted:success
export const setSnackbarMessage = (message, severity) => {
    localStorage.setItem(
        LOCALSTORAGE_MESSAGE_KEY,
        `${message}:${severity}`
    );
};

export const getSnackbarMessage = () => {
    // because of the SSR
    if (typeof localStorage === 'undefined') {
        return [];
    }

    const messageData = localStorage.getItem(LOCALSTORAGE_MESSAGE_KEY);
    if (messageData) {
        return messageData.split(':');
    }

    return [];
};

export const clearSnackbarMessage = () => {
    localStorage.removeItem(LOCALSTORAGE_MESSAGE_KEY);
};

export const getCookieConsent = () => {
    // because of the SSR
    if (typeof localStorage === 'undefined') {
        return null;
    }

    return localStorage.getItem(LOCALSTORAGE_COOKIE_CONSENT_KEY) === LOCALSTORAGE_COOKIE_CONSENT_VALUE;
};

export const setCookieConsentSeen = () => {
    localStorage.setItem(
        LOCALSTORAGE_COOKIE_CONSENT_KEY,
        LOCALSTORAGE_COOKIE_CONSENT_VALUE
    );
};

export const getCategoryPageUrlPath = (category) => `/blog/categories/${category}`;

export const getTagPageUrlPath = (tag) => {
    const tagPath = convertToKebabCase(tag);
    return `/blog/tags/${tagPath}`;
};

export const convertToKebabCase = (string) => string.replace(/([a-z])([A-Z])/g, '$1-$2')
    .replace(/\s+/g, '-')
    .toLowerCase();

export const getAlternateLangLinks = (
    pageContext,
    siteUrl = ''
) =>
    pageContext.intl.languages
        // .filter((language) => language !== pageContext.intl.language)
        .map((language) => {
            let path;
            if (pageContext.otherLanguagesUrl?.length) {
                path = pageContext.otherLanguagesUrl
                    .find((p) => p.startsWith(`/${language}/`));

                if (!path) {
                    return {};
                }
            } else {
                // TODO maybe
                path = `${siteUrl}/${language}${pageContext.intl.originalPath}`;
            }

            return {
                href: path,
                hrefLang: language,
                rel: 'alternate',
            };
        });

// by https://stackoverflow.com/a/63246074/4307769
export const capitalizeString = (string) =>
    string.split(' ').map((item) => item.replace(item.charAt(0), item.charAt(0).toUpperCase())).join(' ');

// by https://stackoverflow.com/a/41267747/4307769
export const truncateStringToWord = (string, length, addEllipsis) => {
    let newString = string;
    if (newString.length <= length) {
        // provided string already short enough
        return newString;
    }

    // cut string down but keep 1 extra character so we can check if
    // a non-word character exists beyond the boundary
    newString = newString.substr(0, length + 1);

    // cut any non-whitespace characters off the end of the string
    if (/[^\s]+$/.test(newString)) {
        newString = newString.replace(/[^\s]+$/, '');
    }

    // cut any remaining non-word characters
    newString = newString.replace(/[^\w]+$/, '');

    const ellipsis = addEllipsis && newString.length > 0 ? '...' : '';

    return `${newString}${ellipsis}`;
};
