import React from 'react';
import PropTypes from 'prop-types';
import Helmet from 'react-helmet';
import { graphql, useStaticQuery } from 'gatsby';
import { useIntl } from 'gatsby-plugin-intl';

// Utils
import { generateSeoFriendlyVideoUrl } from '../utils/gatsby-frontend-helpers';

function SEO({
    description,
    lang,
    meta,
    title,
    robots,
    keywords = [],
    alternateLangLinks = [],
    ogImage,
    ogVideo,
    alternativeOgImage,
    pathname = null,
}) {
    const { site, baseSiteImage } = useStaticQuery(
        graphql`
            query {
                site {
                    siteMetadata {
                        title
                        description
                        author
                        siteUrl
                        defaultLanguage
                        social {
                            twitter
                        }
                    }
                }
                baseSiteImage: file(
                    absolutePath: { regex: "/base_site_image.jpg/" }
                ) {
                    childImageSharp {
                        fixed(width: 1200) {
                            ...GatsbyImageSharpFixed
                        }
                    }
                }
            }
        `
    );

    const intl = useIntl();
    const siteUrl = site.siteMetadata.siteUrl;
    const metaDescription = description || intl.formatMessage({ id: 'description' });
    let currentUrl;
    if (pathname) {
        currentUrl = `${siteUrl}${pathname}`;
    }

    const seoMeta = [
        {
            name: 'viewport',
            content: 'minimum-scale=1, initial-scale=1, width=device-width, shrink-to-fit=no',
        },
        {
            name: 'description',
            content: metaDescription,
        },
        {
            property: 'og:title',
            content: title,
        },
        {
            property: 'og:description',
            content: metaDescription,
        },
        {
            property: 'og:type',
            content: 'website',
        },
        {
            name: 'twitter:card',
            content: 'summary_large_image',
        },
        {
            name: 'twitter:creator',
            content: site.siteMetadata.social.twitter,
        },
        {
            name: 'twitter:title',
            content: title,
        },
        {
            name: 'twitter:description',
            content: metaDescription,
        },
        {
            name: 'content-language',
            content: lang,
        },
        {
            name: 'og:locale',
            content: lang,
        },
        {
            name: 'article:tag',
            content: keywords.join(', '),
        },
        {
            name: 'viewport',
            content: 'width=device-width, initial-scale=1.0, maximum-scale=5.0, user-scalable=no',
        },
    ].concat(meta);

    // og:image order:
    // 1 - ogImage
    // 2 - ogVideo
    // 3 - alternativeOgImage
    let seoImage = `${siteUrl}${ogImage}`;
    if (ogVideo) {
        const video = generateSeoFriendlyVideoUrl(ogVideo);
        if (video) {
            alternateLangLinks.push({
                property: 'og:video',
                href: video,
            });

            if (!ogImage && video?.includes?.('youtube.')) {
                const urlParts = video.split('youtube.com/v/');
                const youtubeId = urlParts?.[1];
                if (youtubeId) {
                    seoImage = `https://img.youtube.com/vi/${youtubeId}/maxresdefault.jpg`;
                }
            }
        }
    }

    if (robots) {
        seoMeta.push({
            property: 'robots',
            content: robots,
        });
    }

    seoImage = seoImage || `${siteUrl}${alternativeOgImage}`;
    if (!seoImage) {
        const defaultImageSrc = baseSiteImage?.childImageSharp?.fixed?.src;
        if (defaultImageSrc) {
            seoImage = defaultImageSrc;
        }
    }

    if (seoImage) {
        alternateLangLinks.push({
            property: 'og:image',
            href: seoImage,
        });

        alternateLangLinks.push({
            property: 'twitter:image',
            href: seoImage,
        });
    }

    const xDefault = alternateLangLinks.find(
        (langLink) => langLink.hrefLang === site.siteMetadata.defaultLanguage
    );

    if (xDefault?.hreflang) {
        alternateLangLinks.push({
            ...xDefault,
            hreflang: 'x-default',
        });
    }

    if (pathname) {
        alternateLangLinks.push({
            property: 'og:url',
            href: currentUrl,
        });
    }

    if (pathname) {
        alternateLangLinks.push({
            rel: 'canonical',
            href: currentUrl,
        });
    }

    return (
        <Helmet
            htmlAttributes={{
                lang,
            }}
            title={title}
            titleTemplate={`%s | ${site.siteMetadata.title}`}
            meta={seoMeta}
            link={alternateLangLinks}
        />
    );
}

SEO.defaultProps = {
    lang: 'en',
    meta: [],
    description: '',
};

SEO.propTypes = {
    description: PropTypes.string,
    lang: PropTypes.string,
    meta: PropTypes.arrayOf(PropTypes.object),
    title: PropTypes.string.isRequired,
    keywords: PropTypes.arrayOf(PropTypes.string),
};

export default SEO;
